import boto3
from botocore.exceptions import ClientError
import time
import random

ec2 = boto3.client('ec2')

def launch_with_quota_awareness(launch_params: dict, max_retries: int = 5):
    """
    Launch an EC2 instance with proper error handling for
    both throttling (retry) and quota exhaustion (fail fast).
    """
    delay = 1.0
    for attempt in range(max_retries):
        try:
            return ec2.run_instances(**launch_params)

        except ClientError as e:
            code = e.response['Error']['Code']

            if code == 'VcpuLimitExceeded':
                # Quota hard stop — retrying does nothing
                raise RuntimeError(
                    "EC2 vCPU limit exceeded. Request a quota increase at: "
                    "https://console.aws.amazon.com/servicequotas/"
                ) from e

            elif code in ('RequestLimitExceeded', 'ThrottlingException'):
                # Transient throttle — back off and retry
                if attempt < max_retries - 1:
                    jitter = random.uniform(0, delay * 0.2)
                    time.sleep(delay + jitter)
                    delay = min(delay * 2, 60)
                    continue
                raise

            else:
                raise

