#!/usr/bin/env python3
"""
Export all non-default quotas for an account/region pair.
Useful for documenting what increases have been applied.
"""
import boto3, json, sys

def export_non_default_quotas(region: str, service_code: str | None = None):
    sq = boto3.client('service-quotas', region_name=region)
    results = []

    list_kwargs = {}
    if service_code:
        list_kwargs['ServiceCode'] = service_code

    paginator = sq.get_paginator('list_service_quotas')

    for page in paginator.paginate(**list_kwargs):
        for quota in page['Quotas']:
            default = quota.get('GlobalQuota', False)
            # Only show quotas that differ from AWS default
            if quota.get('Value') != quota.get('DefaultValue'):
                results.append({
                    'service': quota['ServiceCode'],
                    'quota_name': quota['QuotaName'],
                    'quota_code': quota['QuotaCode'],
                    'default_value': quota.get('DefaultValue'),
                    'applied_value': quota['Value'],
                    'adjustable': quota['Adjustable'],
                })

    return results

if __name__ == '__main__':
    region = sys.argv[1] if len(sys.argv) > 1 else 'us-east-1'
    quotas = export_non_default_quotas(region)
    print(json.dumps(quotas, indent=2))
    print(f"\n{len(quotas)} non-default quotas found in {region}")
